if ( ! defined( 'ABSPATH' ) ) { exit; } class TCT_Reward_Progress_Generator { const ERROR_TYPE_FILESYSTEM = 'filesystem'; const ERROR_TYPE_UNKNOWN = 'unknown'; const BASE_BACKOFF_SECONDS = 30; const MAX_BACKOFF_SECONDS = 600; public static function classify_error( $error_message, $http_code = 0 ) { $msg = strtolower( (string) $error_message ); $fs_needles = array( 'file', 'fopen', 'fwrite', 'file_put_contents', 'permission', 'permissions', 'chmod', 'is_writable', 'not writable', 'directory', 'mkdir', 'wp_upload_dir', 'uploads', 'disk', 'quota', ); foreach ( $fs_needles as $needle ) { if ( '' !== $needle && false !== strpos( $msg, $needle ) ) { return self::ERROR_TYPE_FILESYSTEM; } } return self::ERROR_TYPE_UNKNOWN; } public static function is_retryable_error( $error_type ) { return true; } public static function get_retry_backoff( $error_type, $retry_count ) { $retry_count = max( 1, (int) $retry_count ); $base = self::BASE_BACKOFF_SECONDS * $retry_count; $jitter = function_exists( 'wp_rand' ) ? wp_rand( 0, 10 ) : rand( 0, 10 ); return min( $base + $jitter, self::MAX_BACKOFF_SECONDS ); } public static function log_error( $user_id, $error, $error_type = '', $context = array() ) { if ( ! defined( 'WP_DEBUG' ) || ! WP_DEBUG ) { return; } $log_message = sprintf( 'TCT Reward Progress Generator [User %d]: %s (type: %s)', (int) $user_id, (string) $error, $error_type ? (string) $error_type : self::ERROR_TYPE_UNKNOWN ); if ( ! empty( $context ) ) { $log_message .= ' | Context: ' . wp_json_encode( $context ); } error_log( $log_message ); } public static function resume_failed_job( $user_id ) { $result = array( 'ok' => false, 'error' => '', ); $user_id = (int) $user_id; if ( $user_id <= 0 ) { $result['error'] = 'Invalid user ID.'; return $result; } $job = TCT_Reward::get_generation_job( $user_id ); if ( ! is_array( $job ) ) { $result['error'] = 'No generation job found.'; return $result; } $status = isset( $job['status'] ) ? $job['status'] : ''; if ( TCT_Reward::JOB_STATUS_ERROR !== $status ) { $result['error'] = 'Job is not in error state (current: ' . $status . ').'; return $result; } $job['status'] = TCT_Reward::JOB_STATUS_PENDING; $job['retry_count'] = 0; $job['last_error'] = ''; $job['error_type'] = ''; $job['updated_at'] = time(); TCT_Reward::set_generation_job( $user_id, $job ); TCT_Reward::ensure_cron_scheduled(); $result['ok'] = true; return $result; } public static function check_programmatic_prereqs() { $checks = array( 'gd' => false, 'hex_grid' => false, 'uploads' => false, ); $checks['gd'] = extension_loaded( 'gd' ); if ( ! $checks['gd'] ) { return array( 'ok' => false, 'error' => 'PHP GD extension is not available. Progressive reward images require the GD extension.', 'checks' => $checks, ); } $checks['hex_grid'] = class_exists( 'TCT_Hex_Grid' ); if ( ! $checks['hex_grid'] ) { return array( 'ok' => false, 'error' => 'TCT_Hex_Grid class not available. Please ensure the plugin files are intact.', 'checks' => $checks, ); } if ( ! function_exists( 'wp_upload_dir' ) ) { return array( 'ok' => false, 'error' => 'wp_upload_dir() is not available. WordPress upload functions are required for image generation.', 'checks' => $checks, ); } $uploads = wp_upload_dir(); if ( ! is_array( $uploads ) ) { return array( 'ok' => false, 'error' => 'wp_upload_dir() did not return expected data.', 'checks' => $checks, ); } if ( ! empty( $uploads['error'] ) ) { return array( 'ok' => false, 'error' => 'WordPress uploads directory error: ' . (string) $uploads['error'], 'checks' => $checks, ); } $dir_path = isset( $uploads['path'] ) ? (string) $uploads['path'] : ''; if ( '' === $dir_path ) { return array( 'ok' => false, 'error' => 'WordPress uploads path is empty.', 'checks' => $checks, ); } if ( ! file_exists( $dir_path ) ) { if ( function_exists( 'wp_mkdir_p' ) ) { if ( ! wp_mkdir_p( $dir_path ) ) { return array( 'ok' => false, 'error' => 'Uploads directory is not writable (failed to create: ' . $dir_path . ').', 'checks' => $checks, ); } } else { if ( ! @mkdir( $dir_path, 0755, true ) ) { return array( 'ok' => false, 'error' => 'Uploads directory is not writable (failed to create: ' . $dir_path . ').', 'checks' => $checks, ); } } } $is_writable = function_exists( 'wp_is_writable' ) ? wp_is_writable( $dir_path ) : is_writable( $dir_path ); $checks['uploads'] = (bool) $is_writable; if ( ! $checks['uploads'] ) { return array( 'ok' => false, 'error' => 'Uploads directory is not writable: ' . $dir_path, 'checks' => $checks, ); } return array( 'ok' => true, 'error' => '', 'checks' => $checks, ); } const LOCK_TRANSIENT = 'tct_reward_progress_lock'; const LOCK_TIMEOUT = 300; const STEPS_PER_CRON_RUN = 5; public static function process_queue() { if ( ! class_exists( 'TCT_Admin' ) || ! TCT_Admin::is_progress_images_enabled() ) { return; } if ( get_transient( self::LOCK_TRANSIENT ) ) { return; } set_transient( self::LOCK_TRANSIENT, 1, self::LOCK_TIMEOUT ); try { $pre = self::check_programmatic_prereqs(); if ( empty( $pre['ok'] ) ) { return; } if ( ! class_exists( 'TCT_Reward' ) ) { return; } $users_with_jobs = TCT_Reward::find_users_with_active_jobs( 1 ); if ( empty( $users_with_jobs ) ) { return; } $user_id = (int) $users_with_jobs[0]; for ( $i = 0; $i < self::STEPS_PER_CRON_RUN; $i++ ) { $continue = self::process_user_job( $user_id ); if ( ! $continue ) { break; } } } catch ( Exception $e ) { error_log( 'TCT Reward Progress Generator: Exception in process_queue: ' . $e->getMessage() ); } finally { delete_transient( self::LOCK_TRANSIENT ); } } private static function process_user_job( $user_id ) { $user_id = (int) $user_id; if ( $user_id <= 0 ) { return false; } $job = TCT_Reward::get_generation_job( $user_id ); if ( ! is_array( $job ) ) { return false; } $status = isset( $job['status'] ) ? $job['status'] : ''; if ( ! in_array( $status, array( TCT_Reward::JOB_STATUS_PENDING, TCT_Reward::JOB_STATUS_RUNNING ), true ) ) { return false; } $reward = TCT_Reward::get_active_reward( $user_id ); if ( ! is_array( $reward ) ) { self::mark_job_error( $user_id, $job, 'No active reward found.' ); return false; } $original_attachment_id = isset( $reward['attachment_id'] ) ? (int) $reward['attachment_id'] : 0; if ( $original_attachment_id <= 0 ) { self::mark_job_error( $user_id, $job, 'Reward has no image attached.' ); return false; } $original_path = self::get_attachment_file_path( $original_attachment_id ); if ( ! $original_path ) { self::mark_job_error( $user_id, $job, 'Could not find original image file.' ); return false; } $steps = isset( $job['steps'] ) && is_array( $job['steps'] ) ? $job['steps'] : TCT_Reward::PROGRESS_STEPS; $current_step = isset( $job['current_step'] ) ? (int) $job['current_step'] : 0; if ( $current_step >= count( $steps ) ) { self::mark_job_complete( $user_id, $job ); return false; } if ( $status === TCT_Reward::JOB_STATUS_PENDING ) { $job['status'] = TCT_Reward::JOB_STATUS_RUNNING; } $progress_pct = (float) $steps[ $current_step ]; $step_result = self::process_step_programmatic( $user_id, $reward, $job, $original_path, $progress_pct ); if ( ! empty( $step_result['success'] ) ) { $job['current_step'] = $current_step + 1; $job['updated_at'] = time(); $job['last_error'] = ''; $job['retry_count'] = 0; $job['error_type'] = ''; if ( $job['current_step'] >= count( $steps ) ) { self::mark_job_complete( $user_id, $job ); return false; } $job['status'] = TCT_Reward::JOB_STATUS_RUNNING; TCT_Reward::set_generation_job( $user_id, $job ); wp_schedule_single_event( time() + 5, TCT_Reward::CRON_HOOK_PROGRESS_GENERATION ); return true; } $error_message = isset( $step_result['error'] ) ? (string) $step_result['error'] : 'Unknown error.'; $error_type = self::classify_error( $error_message, 0 ); $job['retry_count'] = isset( $job['retry_count'] ) ? (int) $job['retry_count'] + 1 : 1; $job['last_error'] = $error_message; $job['error_type'] = $error_type; $job['updated_at'] = time(); self::log_error( $user_id, $error_message, $error_type, array( 'step' => $current_step, 'progress' => $progress_pct, 'retry_count' => $job['retry_count'], ) ); $should_retry = ( $job['retry_count'] < TCT_Reward::JOB_MAX_RETRIES ); if ( ! $should_retry ) { $fail_reason = 'Max retries (' . TCT_Reward::JOB_MAX_RETRIES . ') reached. Last error: ' . $error_message; self::mark_job_error( $user_id, $job, $fail_reason ); return false; } $job['status'] = TCT_Reward::JOB_STATUS_RUNNING; TCT_Reward::set_generation_job( $user_id, $job ); $backoff = self::get_retry_backoff( $error_type, $job['retry_count'] ); wp_schedule_single_event( time() + $backoff, TCT_Reward::CRON_HOOK_PROGRESS_GENERATION ); return false; } private static function process_step_programmatic( $user_id, $reward, $job, $original_path, $progress_pct ) { $result = array( 'success' => false, 'error' => '', 'attachment_id' => 0, ); if ( ! class_exists( 'TCT_Hex_Grid' ) ) { $result['error'] = 'TCT_Hex_Grid class not found.'; return $result; } $gen_error = ''; $image_bytes = TCT_Hex_Grid::generate_progress_image( $original_path, $progress_pct, $gen_error ); if ( null === $image_bytes ) { $result['error'] = $gen_error ? $gen_error : 'Unknown image generation error.'; return $result; } $reward_title = isset( $reward['title'] ) ? $reward['title'] : 'Reward'; $original_id = isset( $reward['attachment_id'] ) ? (int) $reward['attachment_id'] : 0; $filename = self::generate_variant_filename( $user_id, $original_id, $progress_pct ); $title = self::generate_variant_title( $reward_title, $progress_pct ); $save_error = ''; $saved = self::save_to_media_library( $image_bytes, $filename, $title, $save_error ); if ( ! $saved || ! isset( $saved['attachment_id'] ) ) { $result['error'] = $save_error ? $save_error : 'Failed to save image to Media Library.'; return $result; } $attachment_id = (int) $saved['attachment_id']; $variants = TCT_Reward::get_progress_variants( $user_id ); $key = self::progress_level_to_key( $progress_pct ); $variants[ $key ] = $attachment_id; TCT_Reward::set_progress_variants( $user_id, $variants ); $result['success'] = true; $result['attachment_id'] = $attachment_id; return $result; } private static function progress_level_to_key( $progress_pct ) { $pct = (float) $progress_pct; if ( floor( $pct ) == $pct ) { return (string) (int) $pct; } return (string) $pct; } public static function save_to_media_library( $image_bytes, $filename, $title, &$error = '' ) { $error = ''; if ( empty( $image_bytes ) ) { $error = 'Image bytes are empty.'; return false; } $uploads = wp_upload_dir(); if ( ! isset( $uploads['path'], $uploads['url'] ) ) { $error = 'wp_upload_dir() did not return expected paths.'; return false; } $dir_path = $uploads['path']; $dir_url = $uploads['url']; if ( ! file_exists( $dir_path ) ) { if ( ! wp_mkdir_p( $dir_path ) ) { $error = 'Failed to create upload directory: ' . $dir_path; return false; } } $file_path = trailingslashit( $dir_path ) . $filename; $file_url = trailingslashit( $dir_url ) . $filename; $written = file_put_contents( $file_path, $image_bytes ); if ( false === $written ) { $error = 'Failed to write file to: ' . $file_path; return false; } $attachment = array( 'post_mime_type' => 'image/png', 'post_title' => sanitize_text_field( $title ), 'post_content' => '', 'post_status' => 'inherit', 'guid' => $file_url, ); $attach_id = wp_insert_attachment( $attachment, $file_path ); if ( is_wp_error( $attach_id ) || ! $attach_id ) { $error = 'wp_insert_attachment failed.'; @unlink( $file_path ); return false; } require_once ABSPATH . 'wp-admin/includes/image.php'; $attach_data = wp_generate_attachment_metadata( $attach_id, $file_path ); if ( is_wp_error( $attach_data ) || ! is_array( $attach_data ) ) { wp_update_attachment_metadata( $attach_id, array() ); } else { wp_update_attachment_metadata( $attach_id, $attach_data ); } return array( 'attachment_id' => $attach_id, 'file_path' => $file_path, ); } public static function get_attachment_file_path( $attachment_id ) { $attachment_id = (int) $attachment_id; if ( $attachment_id <= 0 ) { return null; } $file = get_attached_file( $attachment_id ); if ( ! $file || ! file_exists( $file ) ) { return null; } return $file; } public static function generate_variant_filename( $user_id, $reward_id, $progress_pct ) { $user_id = (int) $user_id; $reward_id = (int) $reward_id; $pct_str = str_replace( '.', '_', (string) $progress_pct ); return sprintf( 'tct_reward_%d_%d_p%s.png', $user_id, $reward_id, $pct_str ); } public static function generate_variant_title( $reward_title, $progress_pct ) { $pct_display = self::format_progress_for_display( $progress_pct ); return sanitize_text_field( $reward_title ) . ' - Progress ' . $pct_display; } public static function format_progress_for_display( $progress_pct ) { $pct = (float) $progress_pct; if ( floor( $pct ) == $pct ) { return (int) $pct . '%'; } return $pct . '%'; } private static function mark_job_complete( $user_id, $job ) { $job['status'] = TCT_Reward::JOB_STATUS_COMPLETE; $job['updated_at'] = time(); $job['last_error'] = ''; $job['error_type'] = ''; TCT_Reward::set_generation_job( (int) $user_id, $job ); } private static function mark_job_error( $user_id, $job, $error ) { $job['status'] = TCT_Reward::JOB_STATUS_ERROR; $job['last_error'] = (string) $error; $job['updated_at'] = time(); if ( empty( $job['error_type'] ) ) { $job['error_type'] = self::classify_error( $job['last_error'], 0 ); } TCT_Reward::set_generation_job( (int) $user_id, $job ); } } 
